The output is:

```dart
// To parse this JSON data, do
//
//     final documentType = documentTypeFromJson(jsonString);

import 'package:json_annotation/json_annotation.dart';
import 'dart:convert';

part 'document_type.g.dart';

DocumentType documentTypeFromJson(String str) => documentTypeValues.map[json.decode(str)]!;

String documentTypeToJson(DocumentType data) => json.encode(documentTypeValues.reverse[data]);

enum DocumentType {
    @JsonValue("abc")
    ABC,
    @JsonValue("def")
    DEF
}

final documentTypeValues = EnumValues({
    "abc": DocumentType.ABC,
    "def": DocumentType.DEF
});

class EnumValues<T> {
    Map<String, T> map;
    late Map<T, String> reverseMap;

    EnumValues(this.map);

    Map<T, String> get reverse {
        reverseMap = map.map((k, v) => MapEntry(v, k));
        return reverseMap;
    }
}
```

This PR is a proposal to add support for emitting a static preview extension on classes and structs. This is useful to quickly create mock data for SwiftUI Previews.

For example this input data:
```JSON
{
  "id": 6570548,
  "name": "John Doe",
  "created_at": "2023-07-06T11:21:49.117Z",
}
```
Would create the following output:

```Swift
// MARK: - UserProfile
struct UserProfile: Codable, Equatable {
    let id: Int?
    let name, createdAt: String?

    enum CodingKeys: String, CodingKey {
        case id, name
        case createdAt = "created_at"
    }
}

extension UserProfile {
    static let preview = UserProfile(
        id: 6570548,
        name: "John Doe",
        createdAt: "2023-07-06T11:21:49.117Z"
    )
}
```

This is a PR regarding the issue https://github.com/quicktype/quicktype/issues/2101

The idea is to provide checks for min and max values for integer (int64_t) and number (double). The generated C++ class `ClassMemberConstraints` can look like this after the generation:

```cpp
class ClassMemberConstraints {
        private:
        std::optional<int64_t> min_int_value;
        std::optional<int64_t> max_int_value;
        std::optional<double> min_double_value;
        std::optional<double> max_double_value;
        std::optional<size_t> min_length;
        std::optional<size_t> max_length;
        std::optional<std::string> pattern;

        public:
        ClassMemberConstraints(
            std::optional<int64_t> min_int_value,
            std::optional<int64_t> max_int_value,
            std::optional<double> min_double_value,
            std::optional<double> max_double_value,
            std::optional<size_t> min_length,
